  ('pukao-6f0ba476-moex-00214', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-112-f6a9be68', 'sub-pukao-6f0ba476-04', NULL, 'single_choice', '衡量所得分配不均度的指標「大島指數」（Oshimaindex），其定義為：', '["所得最高前10%者之所得，占所有人口（家計單位）所得之比例", "所得5等分位組，最高組的所得除以最低組的所得而得出之倍數", "中位數所得除以平均所得", "所得最高前10%者的所得除以平均所得"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:45+00:00", "source_pdf_sha1": "16a639861934", "answer_pdf_sha1": "0cd03ae1c3d9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "412", "s": "1007", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "財政學概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
